"use strict";parserFactory.register("fimfiction.net",()=>new FimfictionParser);class FimfictionParser extends Parser{constructor(){super()}async getChapterUrls(e){return[...e.querySelectorAll("ul.chapters a.chapter-title")].map(e=>util.hyperLinkToChapter(e))}findContent(e){return e.querySelector("div#chapter")}extractTitleImpl(e){return e.querySelector("a.story_name").textContent}extractAuthor(e){let t=e.querySelector("div.info-container a");return null===t?super.extractAuthor(e):t.textContent}removeUnwantedElementsFromContentElement(e){util.removeChildElementsMatchingSelector(e,"h1.chapter-title div[style='float:right']"),super.removeUnwantedElementsFromContentElement(e)}findCoverImageUrl(e){return util.getFirstImgSrc(e,"div.story_container__story_image")}getInformationEpubItemChildNodes(e){let t=e.querySelector("span.likes");return t.textContent="Likes: "+t.textContent,[...e.querySelectorAll("span.description-text, div.chapters-footer div.word_count")].concat(t)}}